{"content": "const express = require('express');
const https = require('https');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.static(path.join(__dirname, 'public')));

/**
 * Helper: make an HTTPS GET request and return parsed JSON.
 * Includes timeout handling.
 */
function httpsGet(url, timeoutMs = 8000) {
  return new Promise((resolve, reject) => {
    const req = https.get(url, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        if (res.statusCode < 200 || res.statusCode >= 300) {
          return reject(new Error(`HTTP ${res.statusCode}: ${res.statusMessage}`));
        }
        try {
          resolve(JSON.parse(data));
        } catch (e) {
          reject(new Error('Failed to parse API response'));
        }
      });
    });
    req.on('error', (err) => reject(new Error(`Network error: ${err.message}`)));
    req.setTimeout(timeoutMs, () => {
      req.destroy();
      reject(new Error('API request timed out'));
    });
  });
}

/**
 * Map WMO weather codes to human-readable conditions.
 */
const WMO_CONDITIONS = {
  0: 'Clear sky',
  1: 'Mainly clear',
  2: 'Partly cloudy',
  3: 'Overcast',
  45: 'Foggy',
  48: 'Foggy',
  51: 'Light drizzle',
  53: 'Moderate drizzle',
  55: 'Dense drizzle',
  56: 'Freezing drizzle',
  57: 'Freezing drizzle',
  61: 'Slight rain',
  63: 'Moderate rain',
  65: 'Heavy rain',
  66: 'Freezing rain',
  67: 'Freezing rain',
  71: 'Slight snow',
  73: 'Moderate snow',
  75: 'Heavy snow',
  77: 'Snow grains',
  80: 'Slight rain showers',
  81: 'Moderate rain showers',
  82: 'Violent rain showers',
  85: 'Slight snow showers',
  86: 'Heavy snow showers',
  95: 'Thunderstorm',
  96: 'Thunderstorm with slight hail',
  99: 'Thunderstorm with heavy hail',
};

function getCondition(code) {
  return WMO_CONDITIONS[code] || 'Unknown';
}

/**
 * GET /health
 */
app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

/**
 * GET /api/weather?city={city_name}
 */
app.get('/api/weather', async (req, res) => {
  const city = (req.query.city || '').trim();
  if (!city) {
    return res.status(400).json({ error: 'City parameter is required' });
  }

  try {
    // Step 1: Geocode city name to coordinates
    const geoUrl = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(city)}&count=1&language=en&format=json`;
    let geoData;
    try {
      geoData = await httpsGet(geoUrl);
    } catch (err) {
      return res.status(502).json({ error: `Geocoding service unavailable: ${err.message}` });
    }

    if (!geoData || !geoData.results || geoData.results.length === 0) {
      return res.status(404).json({ error: `City "${city}" not found` });
    }

    const location = geoData.results[0];
    const { latitude: lat, longitude: lon, name: cityName, country } = location;

    // Step 2: Fetch weather data
    const weatherUrl = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,relative_humidity_2m,apparent_temperature,weather_code,wind_speed_10m&timezone=auto`;
    let weatherData;
    try {
      weatherData = await httpsGet(weatherUrl);
    } catch (err) {
      return res.status(502).json({ error: `Weather service unavailable: ${err.message}` });
    }

    if (!weatherData || !weatherData.current) {
      return res.status(502).json({ error: 'Invalid weather data received' });
    }

    const current = weatherData.current;
    const weatherCode = current.weather_code;

    // Step 3: Build response
    const result = {
      city: cityName,
      country: country || '',
      temperature: current.temperature_2m,
      feels_like: current.apparent_temperature,
      humidity: current.relative_humidity_2m,
      wind_speed: current.wind_speed_10m,
      condition: getCondition(weatherCode),
      weather_code: weatherCode,
    };

    res.json(result);
  } catch (err) {
    console.error('Unexpected error:', err.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(PORT, () => {
  console.log(`Weather app server listening on port ${PORT}`);
});
