{"content": "*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen,
    Ubuntu, Cantarell, 'Helvetica Neue', sans-serif;
  min-height: 100vh;
  background: linear-gradient(135deg, #1e3a5f 0%, #4a90d9 50%, #87ceeb 100%);
  display: flex;
  justify-content: center;
  align-items: flex-start;
  padding: 2rem 1rem;
  color: #333;
}

.container {
  width: 100%;
  max-width: 480px;
  background: rgba(255, 255, 255, 0.95);
  border-radius: 20px;
  padding: 2rem;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.15);
  backdrop-filter: blur(10px);
  transition: all 0.3s ease;
}

header {
  text-align: center;
  margin-bottom: 1.5rem;
}

header h1 {
  font-size: 1.8rem;
  color: #1e3a5f;
  margin-bottom: 0.25rem;
}

.subtitle {
  font-size: 0.9rem;
  color: #666;
}

/* Search bar */
.search-bar {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.search-bar input {
  flex: 1;
  padding: 0.75rem 1rem;
  border: 2px solid #e0e0e0;
  border-radius: 12px;
  font-size: 1rem;
  outline: none;
  transition: border-color 0.2s ease;
}

.search-bar input:focus {
  border-color: #4a90d9;
}

.search-bar button {
  padding: 0.75rem 1.5rem;
  background: #4a90d9;
  color: #fff;
  border: none;
  border-radius: 12px;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s ease, transform 0.1s ease;
}

.search-bar button:hover {
  background: #357abd;
}

.search-bar button:active {
  transform: scale(0.97);
}

/* Preset cities */
.preset-cities {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  justify-content: center;
  margin-bottom: 1.5rem;
}

.preset-btn {
  padding: 0.4rem 1rem;
  background: #e8f0fe;
  color: #1e3a5f;
  border: 1px solid #c4d8f0;
  border-radius: 20px;
  font-size: 0.85rem;
  cursor: pointer;
  transition: background 0.2s ease, transform 0.1s ease;
}

.preset-btn:hover {
  background: #d0e4fc;
}

.preset-btn:active {
  transform: scale(0.95);
}

/* Loading spinner */
.loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 2rem 0;
  gap: 1rem;
}

.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid #e0e0e0;
  border-top: 4px solid #4a90d9;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* Error state */
.error {
  background: #fef2f2;
  color: #dc2626;
  border: 1px solid #fecaca;
  border-radius: 12px;
  padding: 1rem;
  text-align: center;
  font-size: 0.95rem;
  margin-bottom: 1rem;
}

/* Weather card */
.weather-card {
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 0.4s ease, transform 0.4s ease;
}

.weather-card.visible {
  opacity: 1;
  transform: translateY(0);
}

.weather-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 0.5rem;
}

.weather-header h2 {
  font-size: 1.5rem;
  color: #1e3a5f;
}

.country-badge {
  background: #e8f0fe;
  color: #1e3a5f;
  padding: 0.2rem 0.6rem;
  border-radius: 8px;
  font-size: 0.8rem;
  font-weight: 600;
}

.weather-main {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin: 1rem 0;
}

.weather-icon {
  font-size: 4rem;
  line-height: 1;
}

.temperature {
  font-size: 3.5rem;
  font-weight: 700;
  color: #1e3a5f;
}

.temperature::after {
  content: '°C';
  font-size: 1.5rem;
  font-weight: 400;
  vertical-align: super;
}

.feels-like {
  color: #666;
  font-size: 0.95rem;
  margin-bottom: 0.5rem;
}

.feels-like::before {
  content: 'Feels like ';
}

.condition {
  font-size: 1.1rem;
  color: #4a90d9;
  font-weight: 600;
  margin-bottom: 1.25rem;
}

.weather-details {
  display: flex;
  gap: 1rem;
}

.detail {
  flex: 1;
  background: #f0f4f8;
  border-radius: 12px;
  padding: 0.75rem;
  text-align: center;
}

.detail-label {
  display: block;
  font-size: 0.75rem;
  color: #666;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.25rem;
}

.detail-value {
  display: block;
  font-size: 1.1rem;
  font-weight: 600;
  color: #1e3a5f;
}

.hidden {
  display: none !important;
}

/* Responsive */
@media (max-width: 520px) {
  body {
    padding: 1rem 0.5rem;
  }

  .container {
    padding: 1.25rem;
    border-radius: 16px;
  }

  header h1 {
    font-size: 1.4rem;
  }

  .temperature {
    font-size: 2.5rem;
  }

  .weather-icon {
    font-size: 3rem;
  }
}
